package com.nv.commons.dao;import java.sql.Connection;import java.sql.SQLException;import java.sql.Timestamp;import java.util.HashMap;import java.util.List;import java.util.Map;import com.nv.commons.constants.BinaryStatusType;import com.nv.commons.constants.DBOrderType;import com.nv.commons.constants.ProviderStatusType;import com.nv.commons.dto.PageResult;import com.nv.commons.dto.Provider;import com.nv.commons.model.database.BeanConverter;import com.nv.commons.model.database.DBQueryRunner;import com.nv.commons.model.database.DataBeanProcessor;import com.nv.commons.utils.OracleUtils;public class ProviderDAO {		public static List<Provider> findAll(Connection conn) throws SQLException {		String sql = "SELECT * FROM provider ORDER BY display_order";		return DBQueryRunner.getBeanList(conn, Provider.class, sql);	}	public static Map<Integer, Provider> getMap(Connection conn) throws SQLException {		String sql = "SELECT * FROM provider ";		Map<Integer, Provider> resultMap = new HashMap<>();		DataBeanProcessor<Provider> processor = (rs, bean) -> resultMap.put(bean.getId(), bean);		DBQueryRunner.processBeanResult(conn, processor, Provider.class, sql);		return resultMap;	}		public static List<Provider> getProviderByUpdateTime(Connection conn, Timestamp updateTime) throws SQLException {		return DBQueryRunner.getBeanList(conn, Provider.class, "SELECT * FROM provider WHERE update_time > ? ORDER BY UPDATE_TIME", updateTime);	}	}